1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return an empty set when given an empty set of living cells", () => {
6	    expect(nextGeneration(new Set())).toEqual(new Set());
7	  });
8	  it("should return an empty set when a single living cell has no neighbors (underpopulation)", () => {
9	    expect(nextGeneration(new Set(["0,0"]))).toEqual(new Set());
10	  });
11	  it("should kill a living cell with only one live neighbor (underpopulation)", () => {
12	    // Three cells: (5,5) has 1 neighbor -> dies; (5,5)'s only neighbor (6,5) has 2 neighbors;
13	    // Use simpler isolated pair: two diagonal cells far from anything else with 1 neighbor each
14	    // To force non-trivial failure, add a known stable 2x2 block far away that survives
15	    const input = new Set(["0,0", "1,0", "10,10", "11,10", "10,11", "11,11"]);
16	    const expected = new Set(["10,10", "11,10", "10,11", "11,11"]);
17	    expect(nextGeneration(input)).toEqual(expected);
18	  });
19	  it("should keep a living cell alive when it has two live neighbors (survival)", () => {
20	    // A vertical line of 3 cells (blinker): middle cell has 2 live neighbors, survives
21	    // The two end cells have 1 neighbor each, so they die.
22	    // The two horizontal cells (left and right of middle) each have 3 live neighbors, become alive.
23	    // To isolate the survival rule, we need to construct a scenario where a living cell with
24	    // exactly 2 neighbors survives. Use an L-shape: (0,0), (1,0), (0,1) where (0,0) has 2 neighbors.
25	    // (0,0) -> 2 neighbors (1,0) and (0,1) -> survives
26	    // (1,0) -> 1 neighbor (0,0) -> dies
27	    // (0,1) -> 1 neighbor (0,0) -> dies
28	    // (1,1) dead -> 3 neighbors (0,0), (1,0), (0,1) -> becomes alive
29	    // So result includes (0,0) which is the survival case
30	    const input = new Set(["0,0", "1,0", "0,1"]);
31	    const result = nextGeneration(input);
32	    expect(result.has("0,0")).toBe(true);
33	  });
34	  it("should keep a living cell alive when it has three live neighbors (survival)", () => {
35	    // A 2x2 block: each cell has 3 live neighbors -> all survive
36	    // (0,0) has neighbors (1,0), (0,1), (1,1) -> 3 live neighbors -> survives
37	    const input = new Set(["0,0", "1,0", "0,1", "1,1"]);
38	    const result = nextGeneration(input);
39	    expect(result.has("0,0")).toBe(true);
40	  });
41	  it("should kill a living cell with four live neighbors (overpopulation)", () => {
42	    // Center cell (1,1) has 4 live neighbors at the corners (0,0), (2,0), (0,2), (2,2)
43	    // (1,1) should die from overpopulation
44	    // The four corners each have only 1 live neighbor (1,1), so they die from underpopulation
45	    // The four edge-middle dead cells (1,0), (0,1), (2,1), (1,2) each have 3 live neighbors -> reproduce
46	    const input = new Set(["1,1", "0,0", "2,0", "0,2", "2,2"]);
47	    const expected = new Set(["1,0", "0,1", "2,1", "1,2"]);
48	    expect(nextGeneration(input)).toEqual(expected);
49	  });
50	  it("should bring a dead cell to life when it has exactly three live neighbors (reproduction)", () => {
51	    // Dead cell (1,1) has three live neighbors: (0,0), (1,0), (0,1)
52	    // (1,1) should become alive via reproduction
53	    const input = new Set(["0,0", "1,0", "0,1"]);
54	    const result = nextGeneration(input);
55	    expect(result.has("1,1")).toBe(true);
56	  });
57	  it("should handle living cells with negative coordinates", () => {
58	    // A 2x2 block at negative coordinates is stable - all four cells have 3 live neighbors and survive
59	    const input = new Set(["-1,-1", "0,-1", "-1,0", "0,0"]);
60	    const expected = new Set(["-1,-1", "0,-1", "-1,0", "0,0"]);
61	    expect(nextGeneration(input)).toEqual(expected);
62	  });
63	});
64

1	type Cell = string;
2	
3	const keyOf = (x: number, y: number): Cell => `${x},${y}`;
4	
5	const parseCell = (cell: Cell): [number, number] => {
6	  const [x, y] = cell.split(",").map(Number);
7	  return [x, y];
8	};
9	
10	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
11	  [-1, -1], [-1, 0], [-1, 1],
12	  [ 0, -1],          [ 0, 1],
13	  [ 1, -1], [ 1, 0], [ 1, 1],
14	];
15	
16	const neighborsOf = (cell: Cell): Cell[] => {
17	  const [x, y] = parseCell(cell);
18	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => keyOf(x + dx, y + dy));
19	};
20	
21	const countLiveNeighbors = (cell: Cell, livingCells: Set<Cell>): number =>
22	  neighborsOf(cell).filter((neighbor) => livingCells.has(neighbor)).length;
23	
24	const candidateCells = (livingCells: Set<Cell>): Set<Cell> => {
25	  const candidates = new Set<Cell>();
26	  for (const cell of livingCells) {
27	    candidates.add(cell);
28	    for (const neighbor of neighborsOf(cell)) candidates.add(neighbor);
29	  }
30	  return candidates;
31	};
32	
33	const isAliveNextGen = (cell: Cell, livingCells: Set<Cell>): boolean => {
34	  const liveNeighbors = countLiveNeighbors(cell, livingCells);
35	  return liveNeighbors === 3 || (liveNeighbors === 2 && livingCells.has(cell));
36	};
37	
38	export const nextGeneration = (livingCells: Set<Cell>): Set<Cell> =>
39	  new Set(
40	    [...candidateCells(livingCells)].filter((cell) => isAliveNextGen(cell, livingCells))
41	  );
